import React, { useState } from 'react';
import { ShoppingBag, Truck, Store, CreditCard, AlertTriangle, X } from 'lucide-react';

const Carrito = ({ cart, setCart, onCheckout }) => {
  const [modoEntrega, setModoEntrega] = useState('delivery'); // 'delivery' o 'retiro'
  const [paso, setPaso] = useState('revision'); // 'revision' o 'pago'

  const totalPrecio = cart.reduce((acc, p) => acc + p.precioNuevo, 0);
  const totalPeso = cart.reduce((acc, p) => acc + (Number(p.peso) || 0), 0);

  const eliminarItem = (id) => {
    setCart(cart.filter(item => item.id !== id));
  };

  const handlePagar = (e) => {
    e.preventDefault();
    onCheckout(); // Llama a la función de éxito que pasamos por props
  };

  return (
    <div style={cartContainer}>
      <div style={headerCart}>
        <h3 style={title}><ShoppingBag size={20} color="#e67e22" /> Tu Pedido</h3>
        <span style={itemCount}>{cart.length} ítems</span>
      </div>
      
      {/* Selector de Entrega */}
      <div style={deliverySelector}>
        <button 
          onClick={() => setModoEntrega('delivery')}
          style={modoEntrega === 'delivery' ? btnActive : btnInactive}
        >
          <Truck size={16} /> Delivery
        </button>
        <button 
          onClick={() => setModoEntrega('retiro')}
          style={modoEntrega === 'retiro' ? btnActive : btnInactive}
        >
          <Store size={16} /> Retiro
        </button>
      </div>

      {/* Alerta de peso: Solo para Delivery */}
      {modoEntrega === 'delivery' && (
        <div style={totalPeso > 15 ? errorBox : weightBox}>
          <AlertTriangle size={14} /> 
          <span>Peso: <strong>{totalPeso.toFixed(1)}kg</strong> / 15kg</span>
        </div>
      )}

      {paso === 'revision' ? (
        <>
          <div style={listStyle}>
            {cart.map((item) => (
              <div key={item.id} style={itemStyle}>
                <div style={{ flex: 1 }}>
                  <span style={itemName}>{item.producto}</span>
                  <span style={itemWeight}>{item.peso}kg</span>
                </div>
                <strong style={{ marginRight: '10px' }}>${item.precioNuevo}</strong>
                <X size={14} color="#ef4444" cursor="pointer" onClick={() => eliminarItem(item.id)} />
              </div>
            ))}
          </div>
          
          <div style={totalBox}>
            <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '5px' }}>
              <span>Subtotal</span>
              <span>${totalPrecio}</span>
            </div>
            <div style={{ display: 'flex', justifyContent: 'space-between', fontWeight: 'bold', fontSize: '1.2rem' }}>
              <span>Total</span>
              <span style={{ color: '#e67e22' }}>${totalPrecio}</span>
            </div>
          </div>
          
          <button 
            disabled={modoEntrega === 'delivery' && totalPeso > 15}
            onClick={() => setPaso('pago')} 
            style={totalPeso > 15 && modoEntrega === 'delivery' ? btnDisabled : btnPrimario}
          >
            Continuar al Pago
          </button>
        </>
      ) : (
        /* VISTA DE PAGO ONLINE */
        <form onSubmit={handlePagar} style={formPago}>
          <div style={secureBadge}><CreditCard size={14} /> Pago 100% Seguro</div>
          <input placeholder="Nombre en la tarjeta" style={inputStyle} required />
          <input placeholder="Número de tarjeta" style={inputStyle} required maxLength="16" />
          <div style={{ display: 'flex', gap: '10px' }}>
            <input placeholder="MM/AA" style={inputStyle} required maxLength="5" />
            <input placeholder="CVC" style={inputStyle} required maxLength="3" />
          </div>
          <button type="submit" style={btnPagar}>Finalizar Pago</button>
          <button type="button" onClick={() => setPaso('revision')} style={btnVolver}>Volver a la revisión</button>
        </form>
      )}
    </div>
  );
};

// --- ESTILOS ---
const cartContainer = { background: 'white', padding: '20px', borderRadius: '20px', boxShadow: '0 10px 25px rgba(0,0,0,0.1)', width: '320px', position: 'sticky', top: '90px', maxHeight: '80vh', overflowY: 'auto' };
const headerCart = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '15px' };
const title = { display: 'flex', alignItems: 'center', gap: '8px', margin: 0, fontSize: '1.1rem' };
const itemCount = { fontSize: '0.8rem', background: '#f1f5f9', padding: '2px 8px', borderRadius: '10px', color: '#64748b' };
const deliverySelector = { display: 'flex', gap: '8px', marginBottom: '15px', background: '#f8fafc', padding: '4px', borderRadius: '12px' };
const btnActive = { flex: 1, padding: '8px', border: 'none', borderRadius: '8px', background: '#1e293b', color: 'white', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px', fontSize: '0.85rem' };
const btnInactive = { flex: 1, padding: '8px', border: 'none', background: 'transparent', color: '#64748b', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px', fontSize: '0.85rem' };
const weightBox = { background: '#f0fdf4', color: '#166534', padding: '8px 12px', borderRadius: '10px', fontSize: '0.75rem', display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '15px' };
const errorBox = { ...weightBox, background: '#fef2f2', color: '#991b1b', border: '1px solid #fecaca' };
const listStyle = { borderTop: '1px solid #f1f5f9', paddingTop: '10px' };
const itemStyle = { display: 'flex', alignItems: 'center', marginBottom: '12px', fontSize: '0.85rem' };
const itemName = { display: 'block', fontWeight: '600', color: '#1e293b' };
const itemWeight = { fontSize: '0.7rem', color: '#94a3b8' };
const totalBox = { marginTop: '15px', padding: '15px 0', borderTop: '2px dashed #f1f5f9' };
const btnPrimario = { width: '100%', padding: '12px', background: '#e67e22', color: 'white', border: 'none', borderRadius: '10px', fontWeight: 'bold', cursor: 'pointer' };
const btnDisabled = { ...btnPrimario, background: '#cbd5e1', cursor: 'not-allowed' };
const btnPagar = { ...btnPrimario, background: '#10b981' };
const btnVolver = { width: '100%', background: 'none', border: 'none', marginTop: '10px', color: '#64748b', cursor: 'pointer', fontSize: '0.75rem' };
const inputStyle = { width: '100%', padding: '10px', marginBottom: '8px', borderRadius: '8px', border: '1px solid #e2e8f0', boxSizing: 'border-box', fontSize: '0.9rem' };
const secureBadge = { textAlign: 'center', fontSize: '0.7rem', color: '#10b981', marginBottom: '10px', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '5px' };
const formPago = { marginTop: '5px' };

export default Carrito;
